import {apiRequest} from './apiClient';
import type {CursorPage, JournalItem} from './mobileApi';

export type JournalComment = {
  id: string;
  comment?: string;
  created_at?: string;
  parent_id?: string | null;
  post_id?: string;
  user_id?: string;
  users?: {
    id?: string;
    name?: string;
    image_url?: string;
    badge?: string;
  } | null;
  reply_count?: number;
};

type NotificationSource = 'journal' | 'opinion' | string;

const authHeaders = (token?: string): Record<string, string> => {
  if (!token) {
    return {};
  }
  return {Authorization: `Bearer ${token}`};
};

export const socialApi = {
  async likeJournal(
    token: string,
    payload: {
      journalId: string;
      receiverId?: string;
      senderImageUrl?: string;
      sendername?: string;
      senderEmail?: string;
    },
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/like', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });
  },

  async addComment(
    token: string,
    payload: {comments: string; postId: string; receiverId?: string},
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/addComment', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });
  },

  async getComments(
    postId: string,
    cursor: string | null = null,
    limit = 20,
  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
    const params = new URLSearchParams();
    params.set('postId', postId);
    params.set('limit', String(limit));
    if (cursor) {
      params.set('before', cursor);
    }

    return apiRequest<{comments: JournalComment[]; hasMore?: boolean}>(
      `/getComments?${params.toString()}`,
      {method: 'GET'},
    );
  },

  async toggleBookmark(
    token: string,
    payload: {journalId: string},
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/addBoorkmark', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });
  },

  async getBookmarks(
    token: string,
    userId: string,
    cursor: string | null = null,
    limit = 10,
  ): Promise<CursorPage<JournalItem>> {
    const params = new URLSearchParams();
    params.set('userId', userId);
    params.set('limit', String(limit));
    if (cursor) {
      params.set('before', cursor);
    }

    return apiRequest<CursorPage<JournalItem>>(`/getBookmarks?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async getNotificationsCount(
    token: string,
    userId: string,
  ): Promise<{count?: number}> {
    const params = new URLSearchParams();
    params.set('userId', userId);
    return apiRequest<{count?: number}>(`/getCountNotifications?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async markNotificationRead(
    token: string,
    notifId: string,
    source?: NotificationSource,
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/readNotification', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({notifId, source}),
    });
  },

  async deleteNotification(
    token: string,
    notifId: string,
    source?: NotificationSource,
  ): Promise<{message?: string}> {
    const suffix = source
      ? `/deleteNotification/${encodeURIComponent(notifId)}?source=${encodeURIComponent(source)}`
      : `/deleteNotification/${encodeURIComponent(notifId)}`;

    return apiRequest<{message?: string}>(suffix, {
      method: 'DELETE',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async getUnreadNotifications(
    token: string,
    cursor: string | null = null,
    limit = 10,
  ): Promise<CursorPage<unknown>> {
    const params = new URLSearchParams();
    params.set('limit', String(limit));
    if (cursor) {
      params.set('before', cursor);
    }

    return apiRequest<CursorPage<unknown>>(`/getUnreadNotification?${params.toString()}`, {
      method: 'GET',
      headers: {
        ...authHeaders(token),
      },
    });
  },

  async toggleReaction(
    token: string,
    payload: {
      journalId: string;
      receiverId: string;
      reactionType: string;
    },
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/reaction', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });
  },

  async createRepost(
    token: string,
    payload: {sourceJournalId: string; caption?: string},
  ): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/repost', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });
  },
};

