  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  ActivityIndicator,
  4→  Alert,
  5→  Image,
  6→  Pressable,
  7→  ScrollView,
  8→  StyleSheet,
  9→  Text,
 10→  TextInput,
 11→  View,
 12→} from 'react-native';
 13→import {useMutation, useQuery} from '@tanstack/react-query';
 14→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 15→import {SafeAreaView} from 'react-native-safe-area-context';
 16→import {Avatar} from '../../components/Avatar';
 17→import {BadgeCheckIcon} from '../../components/icons';
 18→import {ActionBar} from '../../components/PostCard/ActionBar';
 19→import {PrimaryButton} from '../../components/PrimaryButton';
 20→import {SkeletonLoader} from '../../components/SkeletonLoader';
 21→import {LexicalRenderer} from '../../lib/content/LexicalRenderer';
 22→import {RelatedPosts} from '../../components/Discovery/RelatedPosts';
 23→import {useAuth} from '../../features/auth/AuthProvider';
 24→import {useTheme} from '../../theme/ThemeProvider';
 25→import {fonts, typeScale} from '../../theme/typography';
 26→import {spacing, radii} from '../../theme/spacing';
 27→import {mobileApi} from '../../lib/api/mobileApi';
 28→import {socialApi} from '../../lib/api/socialApi';
 29→import {queryClient} from '../../lib/queryClient';
 30→import type {RootStackParamList} from '../../navigation/types';
 31→
 32→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 33→
 34→const toCount = (value: unknown): number | null => {
 35→  const parsed = Number(value);
 36→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 37→};
 38→
 39→const resolveCount = (
 40→  aggregate: Array<{count?: number}> | undefined,
 41→  fallback?: number,
 42→): number => {
 43→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 44→};
 45→
 46→const formatRelativeDate = (value: string | undefined): string => {
 47→  if (!value) return '';
 48→  const date = new Date(value);
 49→  if (Number.isNaN(date.getTime())) return value;
 50→  const now = Date.now();
 51→  const diff = now - date.getTime();
 52→  const mins = Math.floor(diff / 60000);
 53→  if (mins < 1) return 'Just now';
 54→  if (mins < 60) return `${mins}m ago`;
 55→  const hours = Math.floor(mins / 60);
 56→  if (hours < 24) return `${hours}h ago`;
 57→  const days = Math.floor(hours / 24);
 58→  if (days < 7) return `${days}d ago`;
 59→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 60→};
 61→
 62→const extractBannerImage = (content: string | null | undefined): string | null => {
 63→  if (!content) return null;
 64→  try {
 65→    const parsed = JSON.parse(content);
 66→    const findImage = (node: any): string | null => {
 67→      if (node.type === 'image' && node.src) return node.src;
 68→      if (node.children) {
 69→        for (const child of node.children) {
 70→          const found = findImage(child);
 71→          if (found) return found;
 72→        }
 73→      }
 74→      return null;
 75→    };
 76→    return findImage(parsed.root ?? parsed);
 77→  } catch {
 78→    return null;
 79→  }
 80→};
 81→
 82→export function PostDetailScreen({route}: Props) {
 83→  const {user, session} = useAuth();
 84→  const {colors} = useTheme();
 85→  const {journalId} = route.params;
 86→  const token = session?.access_token ?? '';
 87→  const [commentInput, setCommentInput] = useState('');
 88→  const [repostCaption, setRepostCaption] = useState('');
 89→  const [showRepost, setShowRepost] = useState(false);
 90→
 91→  const detailQuery = useQuery({
 92→    queryKey: ['journal', journalId, user?.id],
 93→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 94→  });
 95→
 96→  const commentsQuery = useQuery({
 97→    queryKey: ['journal-comments', journalId],
 98→    queryFn: () => socialApi.getComments(journalId, null, 20),
 99→  });
100→
101→  const reactionMutation = useMutation({
102→    mutationFn: async (reactionType: string) => {
103→      const journal = detailQuery.data?.journal;
104→      const receiverId = journal?.user_id ?? journal?.users?.id;
105→      if (!token) throw new Error('Please log in to react.');
106→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
107→      return socialApi.toggleReaction(token, {
108→        journalId: journal.id,
109→        receiverId,
110→        reactionType,
111→      });
112→    },
113→    onSuccess: () => {
114→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
115→      queryClient.invalidateQueries({queryKey: ['feed']});
116→    },
117→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
118→  });
119→
120→  const bookmarkMutation = useMutation({
121→    mutationFn: async () => {
122→      if (!token) throw new Error('Please log in to bookmark.');
123→      return socialApi.toggleBookmark(token, {journalId});
124→    },
125→    onSuccess: () => {
126→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
127→      queryClient.invalidateQueries({queryKey: ['feed']});
128→    },
129→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
130→  });
131→
132→  const addCommentMutation = useMutation({
133→    mutationFn: async () => {
134→      const body = commentInput.trim();
135→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
136→      if (!token) throw new Error('Please log in to comment.');
137→      if (!body) throw new Error('Comment cannot be empty.');
138→      if (!receiverId) throw new Error('Missing journal owner.');
139→      return socialApi.addComment(token, {comments: body, postId: journalId, receiverId});
140→    },
141→    onSuccess: () => {
142→      setCommentInput('');
143→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
144→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
145→    },
146→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
147→  });
148→
149→  const repostMutation = useMutation({
150→    mutationFn: async () => {
151→      if (!token) throw new Error('Please log in to repost.');
152→      return socialApi.createRepost(token, {
153→        sourceJournalId: journalId,
154→        caption: repostCaption.trim() || undefined,
155→      });
156→    },
157→    onSuccess: () => {
158→      setRepostCaption('');
159→      setShowRepost(false);
160→      Alert.alert('Reposted', 'Post was reposted to your feed.');
161→      queryClient.invalidateQueries({queryKey: ['feed']});
162→    },
163→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
164→  });
165→
166→  const journal = detailQuery.data?.journal;
167→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
168→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
169→  const bookmarkCount = resolveCount(journal?.bookmark_count);
170→  const comments = commentsQuery.data?.comments ?? [];
171→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
172→
173→  if (detailQuery.isLoading) {
174→    return (
175→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
176→        <View style={styles.loadingContainer}>
177→          <SkeletonLoader height={200} borderRadius={0} />
178→          <View style={styles.contentPadding}>
179→            <SkeletonLoader width="70%" height={24} />
180→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
181→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
182→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
183→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
184→          </View>
185→        </View>
186→      </SafeAreaView>
187→    );
188→  }
189→
190→  if (detailQuery.isError) {
191→    return (
192→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
193→        <View style={styles.contentPadding}>
194→          <Text style={[styles.errorText, {color: colors.danger}]}>
195→            Unable to load this post.
196→          </Text>
197→        </View>
198→      </SafeAreaView>
199→    );
200→  }
201→
202→  return (
203→    <ScrollView
204→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
205→      showsVerticalScrollIndicator={false}>
206→      {/* Banner image */}
207→      {bannerImage && (
208→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
209→      )}
210→
211→      <View style={styles.contentPadding}>
212→        {/* Title */}
213→        <Text style={[styles.title, {color: colors.textHeading}]}>
214→          {journal?.title || 'Untitled Post'}
215→        </Text>
216→
217→        {/* Author section */}
218→        <View style={styles.authorRow}>
219→          <Avatar
220→            uri={journal?.users?.image_url}
221→            name={journal?.users?.name}
222→            size={36}
223→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
224→          />
225→          <View style={styles.authorInfo}>
226→            <View style={styles.authorNameRow}>
227→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
228→                {journal?.users?.name || 'Unknown author'}
229→              </Text>
230→              {journal?.users?.badge ? (
231→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
232→              ) : null}
233→            </View>
234→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
235→              {formatRelativeDate(journal?.created_at)}
236→            </Text>
237→          </View>
238→        </View>
239→
240→        {/* Action bar */}
241→        <ActionBar
242→          likeCount={likeCount}
243→          commentCount={commentCount}
244→          bookmarkCount={bookmarkCount}
245→          isLiked={journal?.has_liked}
246→          isBookmarked={journal?.has_bookmarked}
247→          userReaction={journal?.user_reaction}
248→          onReact={type => reactionMutation.mutate(type)}
249→          onComment={() => {/* scroll to comments */}}
250→          onBookmark={() => bookmarkMutation.mutate()}
251→          onRepost={() => setShowRepost(!showRepost)}
252→        />
253→
254→        {/* Repost section */}
255→        {showRepost && (
256→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
257→            <TextInput
258→              value={repostCaption}
259→              onChangeText={setRepostCaption}
260→              placeholder="Add an optional caption"
261→              placeholderTextColor={colors.textFaint}
262→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
263→              maxLength={280}
264→              multiline
265→            />
266→            <PrimaryButton
267→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
268→              onPress={() => repostMutation.mutate()}
269→              disabled={repostMutation.isPending}
270→            />
271→          </View>
272→        )}
273→
274→        {/* Divider */}
275→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
276→
277→        {/* Content body */}
278→        <LexicalRenderer content={journal?.content} />
279→
280→        {/* Related posts */}
281→        <RelatedPosts journalId={journalId} />
282→
283→        {/* Divider */}
284→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
285→
286→        {/* Comments section */}
287→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
288→          Comments ({commentCount})
289→        </Text>
290→
291→        {commentsQuery.isLoading ? (
292→          <View style={styles.commentLoading}>
293→            <ActivityIndicator color={colors.loaderColor} />
294→          </View>
295→        ) : comments.length === 0 ? (
296→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
297→            No comments yet. Be the first!
