import React from 'react';
import Svg, {Path, G, Circle, Line, Polyline, Rect} from 'react-native-svg';

export interface IconProps {
  size?: number;
  color?: string;
  filled?: boolean;
  strokeWidth?: number;
}

const defaults = {size: 24, color: '#888', strokeWidth: 1.8};

function I({
  size = defaults.size,
  color = defaults.color,
  children,
}: IconProps & {children: React.ReactNode}) {
  return (
    <Svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={defaults.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round">
      {children}
    </Svg>
  );
}

export function HeartIcon({size, color, filled, strokeWidth}: IconProps) {
  const sw = strokeWidth ?? defaults.strokeWidth;
  return (
    <Svg
      width={size ?? defaults.size}
      height={size ?? defaults.size}
      viewBox="0 0 24 24"
      fill={filled ? color ?? defaults.color : 'none'}
      stroke={color ?? defaults.color}
      strokeWidth={sw}
      strokeLinecap="round"
      strokeLinejoin="round">
      <Path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
    </Svg>
  );
}

export function CommentIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function BookmarkIcon({size, color, filled}: IconProps) {
  return (
    <Svg
      width={size ?? defaults.size}
      height={size ?? defaults.size}
      viewBox="0 0 24 24"
      fill={filled ? color ?? defaults.color : 'none'}
      stroke={color ?? defaults.color}
      strokeWidth={defaults.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round">
      <Path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
    </Svg>
  );
}

export function RepostIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Polyline points="17 1 21 5 17 9" stroke={color ?? defaults.color} />
      <Path d="M3 11V9a4 4 0 0 1 4-4h14" stroke={color ?? defaults.color} />
      <Polyline points="7 23 3 19 7 15" stroke={color ?? defaults.color} />
      <Path d="M21 13v2a4 4 0 0 1-4 4H3" stroke={color ?? defaults.color} />
    </I>
  );
}

export function SearchIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="11" cy="11" r="8" stroke={color ?? defaults.color} />
      <Line x1="21" y1="21" x2="16.65" y2="16.65" stroke={color ?? defaults.color} />
    </I>
