}

export function BellIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
      <Path d="M13.73 21a2 2 0 0 1-3.46 0" stroke={color ?? defaults.color} />
    </I>
