export function HomeIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
      <Polyline points="9 22 9 12 15 12 15 22" stroke={color ?? defaults.color} />
