export function BookIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20" stroke={color ?? defaults.color} />
      <Path
        d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"
        stroke={color ?? defaults.color}
      />
