}

export function ShareIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="18" cy="5" r="3" stroke={color ?? defaults.color} />
      <Circle cx="6" cy="12" r="3" stroke={color ?? defaults.color} />
      <Circle cx="18" cy="19" r="3" stroke={color ?? defaults.color} />
      <Line x1="8.59" y1="13.51" x2="15.42" y2="17.49" stroke={color ?? defaults.color} />
      <Line x1="15.41" y1="6.51" x2="8.59" y2="10.49" stroke={color ?? defaults.color} />
    </I>
  );
}

export function PlusIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Line x1="12" y1="5" x2="12" y2="19" stroke={color ?? defaults.color} />
      <Line x1="5" y1="12" x2="19" y2="12" stroke={color ?? defaults.color} />
