  const fill = badge === 'legend' ? '#FFD700' : '#9B59FF';
  return (
    <Svg width={size} height={size} viewBox="0 0 24 24" fill="none">
      <Circle cx="12" cy="12" r="12" fill={fill} />
      <Path
        d="M7 12.5l3.5 3.5 6.5-7"
        stroke="#FFFFFF"
        strokeWidth={2.5}
        strokeLinecap="round"
        strokeLinejoin="round"
