132→        <View style={styles.commentActions}>
133→          {isLoggedIn && (
134→            <Pressable
135→              style={styles.actionButton}
136→              onPress={() => onReply(comment.id, userName)}>
137→              <ReplyIcon size={14} color={colors.textMuted} />
138→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
139→                Reply
140→              </Text>
141→            </Pressable>
142→          )}
143→          {replyCount > 0 && (
144→            <Pressable
145→              style={styles.actionButton}
146→              onPress={() => onToggleReplies(comment.id)}>
147→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
148→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
149→              </Text>
