195→export function PostDetailScreen({route}: Props) {
196→  const {user, session} = useAuth();
197→  const {colors} = useTheme();
198→  const {journalId} = route.params;
199→  const token = session?.access_token ?? '';
200→  const [commentInput, setCommentInput] = useState('');
201→  const [repostCaption, setRepostCaption] = useState('');
202→  const [showRepost, setShowRepost] = useState(false);
203→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
204→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
205→  const scrollViewRef = useRef<ScrollView>(null);
206→  const inputRef = useRef<TextInput>(null);
207→
208→  const handleReply = useCallback((commentId: string, userName: string) => {
209→    setReplyingTo({id: commentId, userName});
210→    setTimeout(() => {
211→      inputRef.current?.focus();
212→      scrollViewRef.current?.scrollToEnd({animated: true});
213→    }, 100);
214→  }, []);
215→
216→  const handleToggleReplies = useCallback((commentId: string) => {
217→    setExpandedReplies(prev => {
218→      const next = new Set(prev);
219→      if (next.has(commentId)) {
220→        next.delete(commentId);
221→      } else {
222→        next.add(commentId);
223→      }
224→      return next;
225→    });
226→  }, []);
227→
228→  const detailQuery = useQuery({
229→    queryKey: ['journal', journalId, user?.id],
230→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
231→  });
232→
233→  const commentsQuery = useQuery({
234→    queryKey: ['journal-comments', journalId],
235→    queryFn: () => socialApi.getComments(journalId, null, 20),
236→  });
237→
238→  const reactionMutation = useMutation({
239→    mutationFn: async (reactionType: string) => {
240→      const journal = detailQuery.data?.journal;
241→      const receiverId = journal?.user_id ?? journal?.users?.id;
242→      if (!token) throw new Error('Please log in to react.');
243→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
244→      return socialApi.toggleReaction(token, {
245→        journalId: journal.id,
246→        receiverId,
247→        reactionType,
248→      });
249→    },
250→    onSuccess: () => {
251→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
252→      queryClient.invalidateQueries({queryKey: ['feed']});
253→    },
254→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
255→  });
256→
257→  const bookmarkMutation = useMutation({
258→    mutationFn: async () => {
259→      if (!token) throw new Error('Please log in to bookmark.');
260→      return socialApi.toggleBookmark(token, {journalId});
261→    },
262→    onSuccess: () => {
263→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
264→      queryClient.invalidateQueries({queryKey: ['feed']});
265→    },
266→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
267→  });
268→
269→  const addCommentMutation = useMutation({
270→    mutationFn: async () => {
271→      const body = commentInput.trim();
272→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
273→      if (!token) throw new Error('Please log in to comment.');
274→      if (!body) throw new Error('Comment cannot be empty.');
275→      if (!receiverId) throw new Error('Missing journal owner.');
276→      return socialApi.addComment(token, {
277→        comments: body,
278→        postId: journalId,
279→        receiverId,
280→        parentId: replyingTo?.id,
281→      });
282→    },
283→    onSuccess: () => {
284→      const parentId = replyingTo?.id;
285→      setCommentInput('');
286→      setReplyingTo(null);
287→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
288→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
289→      if (parentId) {
290→        queryClient.invalidateQueries({queryKey: ['comment-replies', parentId]});
291→      }
292→    },
293→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
294→  });
295→
296→  const repostMutation = useMutation({
297→    mutationFn: async () => {
298→      if (!token) throw new Error('Please log in to repost.');
299→      return socialApi.createRepost(token, {
300→        sourceJournalId: journalId,
301→        caption: repostCaption.trim() || undefined,
302→      });
303→    },
304→    onSuccess: () => {
305→      setRepostCaption('');
306→      setShowRepost(false);
307→      Alert.alert('Reposted', 'Post was reposted to your feed.');
308→      queryClient.invalidateQueries({queryKey: ['feed']});
309→    },
310→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
311→  });
312→
313→  const journal = detailQuery.data?.journal;
314→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
315→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
316→  const bookmarkCount = resolveCount(journal?.bookmark_count);
317→  const comments = commentsQuery.data?.comments ?? [];
318→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
319→
320→  if (detailQuery.isLoading) {
321→    return (
322→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
323→        <View style={styles.loadingContainer}>
324→          <SkeletonLoader height={200} borderRadius={0} />
325→          <View style={styles.contentPadding}>
326→            <SkeletonLoader width="70%" height={24} />
