328→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
329→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
330→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
331→          </View>
332→        </View>
333→      </SafeAreaView>
334→    );
335→  }
336→
337→  if (detailQuery.isError) {
338→    return (
339→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
340→        <View style={styles.contentPadding}>
341→          <Text style={[styles.errorText, {color: colors.danger}]}>
342→            Unable to load this post.
343→          </Text>
344→        </View>
345→      </SafeAreaView>
346→    );
347→  }
348→
349→  return (
350→    <ScrollView
351→      ref={scrollViewRef}
352→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
353→      showsVerticalScrollIndicator={false}>
354→      {/* Banner image */}
355→      {bannerImage && (
356→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
357→      )}
358→
359→      <View style={styles.contentPadding}>
360→        {/* Title */}
361→        <Text style={[styles.title, {color: colors.textHeading}]}>
362→          {journal?.title || 'Untitled Post'}
363→        </Text>
364→
365→        {/* Author section */}
366→        <View style={styles.authorRow}>
367→          <Avatar
368→            uri={journal?.users?.image_url}
369→            name={journal?.users?.name}
370→            size={36}
371→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
372→          />
373→          <View style={styles.authorInfo}>
374→            <View style={styles.authorNameRow}>
375→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
376→                {journal?.users?.name || 'Unknown author'}
377→              </Text>
378→              {journal?.users?.badge ? (
379→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
380→              ) : null}
381→            </View>
382→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
383→              {formatRelativeDate(journal?.created_at)}
384→            </Text>
385→          </View>
386→        </View>
387→
388→        {/* Action bar */}
389→        <ActionBar
390→          likeCount={likeCount}
391→          commentCount={commentCount}
392→          bookmarkCount={bookmarkCount}
393→          isLiked={journal?.has_liked}
394→          isBookmarked={journal?.has_bookmarked}
395→          userReaction={journal?.user_reaction}
396→          onReact={type => reactionMutation.mutate(type)}
397→          onComment={() => {/* scroll to comments */}}
398→          onBookmark={() => bookmarkMutation.mutate()}
399→          onRepost={() => setShowRepost(!showRepost)}
400→        />
401→
402→        {/* Repost section */}
403→        {showRepost && (
