416→              onPress={() => repostMutation.mutate()}
417→              disabled={repostMutation.isPending}
418→            />
419→          </View>
420→        )}
421→
422→        {/* Divider */}
423→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
424→
