436→          Comments ({commentCount})
437→        </Text>
438→
439→        {commentsQuery.isLoading ? (
440→          <View style={styles.commentLoading}>
441→            <ActivityIndicator color={colors.loaderColor} />
442→          </View>
443→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
444→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
445→            No comments yet. Be the first!
446→          </Text>
