301→        sourceJournalId: journalId,
302→        caption: repostCaption.trim() || undefined,
303→      });
304→    },
305→    onSuccess: () => {
306→      setRepostCaption('');
307→      setShowRepost(false);
308→      Alert.alert('Reposted', 'Post was reposted to your feed.');
